// SocialLoginModule.kt
package com.example.sociallogin

import android.content.Context
import android.content.Intent
import androidx.activity.result.ActivityResultLauncher
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.android.gms.tasks.Task

class SocialLoginModule(private val context: Context) {

    private val encryptedPrefs by lazy {
        val masterKey = MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()

        EncryptedSharedPreferences.create(
            context,
            "social_login_secure_prefs",
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    private val facebookCallbackManager: CallbackManager = CallbackManager.Factory.create()
    private var googleSignInClient: GoogleSignInClient? = null

    private var loginCallback: SocialLoginCallback? = null

    // Load secrets from environment or secure configuration
    private val facebookAppId: String by lazy {
        System.getenv("FACEBOOK_APP_ID") 
            ?: throw SecurityException("FACEBOOK_APP_ID must be set in environment variables")
    }

    private val facebookAppSecret: String by lazy {
        System.getenv("FACEBOOK_APP_SECRET") 
            ?: throw SecurityException("FACEBOOK_APP_SECRET must be set in environment variables")
    }

    private val googleClientId: String by lazy {
        System.getenv("GOOGLE_CLIENT_ID") 
            ?: throw SecurityException("GOOGLE_CLIENT_ID must be set in environment variables")
    }

    private val googleClientSecret: String by lazy {
        System.getenv("GOOGLE_CLIENT_SECRET") 
            ?: throw SecurityException("GOOGLE_CLIENT_SECRET must be set in environment variables")
    }

    init {
        initializeGoogleSignIn()
    }

    private fun initializeGoogleSignIn() {
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestEmail()
            .requestIdToken(googleClientId)
            .build()

        googleSignInClient = GoogleSignIn.getClient(context, gso)
    }

    fun loginWithFacebook(activityResultLauncher: ActivityResultLauncher<Intent>? = null) {
        LoginManager.getInstance().registerCallback(facebookCallbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    val accessToken = result.accessToken.token
                    storeAccessToken("facebook", accessToken)
                    loginCallback?.onLoginSuccess("facebook", accessToken)
                }

                override fun onCancel() {
                    loginCallback?.onLoginCancelled("facebook")
                }

                override fun onError(error: FacebookException) {
                    loginCallback?.onLoginError("facebook", error.message ?: "Unknown error")
                }
            })

        LoginManager.getInstance().logInWithReadPermissions(
            null,
            listOf("email", "public_profile")
        )
    }

    fun loginWithGoogle(activityResultLauncher: ActivityResultLauncher<Intent>) {
        val signInIntent = googleSignInClient?.signInIntent
        signInIntent?.let {
            activityResultLauncher.launch(it)
        }
    }

    fun handleGoogleSignInResult(data: Intent?) {
        val task = GoogleSignIn.getSignedInAccountFromIntent(data)
        handleSignInResult(task)
    }

    private fun handleSignInResult(completedTask: Task<GoogleSignInAccount>) {
        try {
            val account = completedTask.getResult(ApiException::class.java)
            val idToken = account?.idToken
            
            if (idToken != null) {
                storeAccessToken("google", idToken)
                loginCallback?.onLoginSuccess("google", idToken)
            } else {
                loginCallback?.onLoginError("google", "Failed to retrieve ID token")
            }
        } catch (e: ApiException) {
            loginCallback?.onLoginError("google", e.message ?: "Sign in failed")
        }
    }

    fun handleFacebookActivityResult(requestCode: Int, resultCode: Int, data: Intent?): Boolean {
        return facebookCallbackManager.onActivityResult(requestCode, resultCode, data)
    }

    private fun storeAccessToken(provider: String, token: String) {
        encryptedPrefs.edit().apply {
            putString("${provider}_access_token", token)
            putLong("${provider}_token_timestamp", System.currentTimeMillis())
            apply()
        }
    }

    fun getStoredAccessToken(provider: String): String? {
        return encryptedPrefs.getString("${provider}_access_token", null)
    }

    fun clearStoredTokens() {
        encryptedPrefs.edit().clear().apply()
    }

    fun logout(provider: String) {
        when (provider) {
            "facebook" -> {
                LoginManager.getInstance().logOut()
            }
            "google" -> {
                googleSignInClient?.signOut()
            }
        }
        
        encryptedPrefs.edit().apply {
            remove("${provider}_access_token")
            remove("${provider}_token_timestamp")
            apply()
        }
    }

    fun setLoginCallback(callback: SocialLoginCallback) {
        this.loginCallback = callback
    }

    interface SocialLoginCallback {
        fun onLoginSuccess(provider: String, token: String)
        fun onLoginError(provider: String, error: String)
        fun onLoginCancelled(provider: String)
    }
}

// SocialLoginActivity.kt
package com.example.sociallogin

import android.content.Intent
import android.os.Bundle
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity

class SocialLoginActivity : AppCompatActivity() {

    private lateinit var socialLoginModule: SocialLoginModule

    private val googleSignInLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        socialLoginModule.handleGoogleSignInResult(result.data)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        socialLoginModule = SocialLoginModule(this)
        
        socialLoginModule.setLoginCallback(object : SocialLoginModule.SocialLoginCallback {
            override fun onLoginSuccess(provider: String, token: String) {
                handleLoginSuccess(provider, token)
            }

            override fun onLoginError(provider: String, error: String) {
                handleLoginError(provider, error)
            }

            override fun onLoginCancelled(provider: String) {
                handleLoginCancelled(provider)
            }
        })
    }

    fun initiateGoogleLogin() {
        socialLoginModule.loginWithGoogle(googleSignInLauncher)
    }

    fun initiateFacebookLogin() {
        socialLoginModule.loginWithFacebook()
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        socialLoginModule.handleFacebookActivityResult(requestCode, resultCode, data)
    }

    private fun handleLoginSuccess(provider: String, token: String) {
        // Token is already securely stored in EncryptedSharedPreferences
        // Do not log the token
    }

    private fun handleLoginError(provider: String, error: String) {
        // Handle error without logging sensitive information
    }

    private fun handleLoginCancelled(provider: String) {
        // Handle cancellation
    }

    fun logoutFromProvider(provider: String) {
        socialLoginModule.logout(provider)
    }

    fun clearAllTokens() {
        socialLoginModule.clearStoredTokens()
    }
}

